def group_even_runs(nums: list[int]) -> list[list[int]]:
    result = []
    current_run = []
    for num in nums:
        if num % 2 == 0:
            current_run.append(num)
        else:
            if current_run:
                result.append(current_run)
            current_run = []
    if current_run:
        result.append(current_run)
    return result
